import io.github.resilience4j.bulkhead.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Duration;

@Service
public class ManualBulkheadService {
    private final Bulkhead bulkhead = Bulkhead.of("test",
        BulkheadConfig.custom()
            .maxConcurrentCalls(2) // small for testing
            .maxWaitDuration(Duration.ofMillis(0)) // no wait
            .build());

    public String callGateway(String gatewayName) {
        if (!bulkhead.tryAcquirePermission()) {
            // No slot available: return fallback immediately
            return "FALLBACK: " + gatewayName + " bulkhead full";
        }
        try {
            // Simulate gateway call:
            return "SUCCESS: " + gatewayName + " responded";
        } finally {
            bulkhead.onComplete(); // ALWAYS release the permit
        }
    }

    public Bulkhead.Metrics getMetrics() {
        return bulkhead.getMetrics();
    }
}

@SpringBootTest
class ManualBulkheadTest {
    @Autowired ManualBulkheadService svc;

    @Test void normalCall_succeeds(){
        String result = svc.callGateway("HDFC");
        assertEquals("SUCCESS: HDFC responded", result);
    }

    @Test void permitsReleased_afterCall(){
        svc.callGateway("HDFC"); // acquire + release
        // Permit should be released by onComplete in finally:
        assertEquals(2, svc.getMetrics().getMaxAllowedConcurrentCalls());
        // Available permits back to 2 after the call completed
        assertEquals(2, svc.getMetrics().getAvailableConcurrentCalls());
    }
}

import io.github.resilience4j.bulkhead.annotation.Bulkhead;
import io.github.resilience4j.bulkhead.BulkheadFullException;
import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import io.github.resilience4j.circuitbreaker.CallNotPermittedException;
import org.springframework.stereotype.*;
