record GatewayResponse(String status, String message, String gateway){}

@Service
public class HdfcGatewayService {

    // Outer: CircuitBreaker (stops calls when too many fail)
    // Inner: Bulkhead (limits concurrent calls)
    @CircuitBreaker(name="hdfc-gateway", fallbackMethod="hdfcFallback")
    @Bulkhead(name="hdfc-gateway", fallbackMethod="hdfcFallback")
    public GatewayResponse charge(String merchantId, long amountPaise) {
        // Call HDFC gateway:
        return new GatewayResponse("SUCCESS", "Payment charged via HDFC", "HDFC");
    }

    // Fallback for BulkheadFullException:
    public GatewayResponse hdfcFallback(String merchantId, long amount, BulkheadFullException ex) {
        return new GatewayResponse("FALLBACK", "HDFC at capacity, try again", "HDFC-FALLBACK");
    }

    // Fallback for CallNotPermittedException (circuit open):
    public GatewayResponse hdfcFallback(String merchantId, long amount, CallNotPermittedException ex) {
        return new GatewayResponse("CIRCUIT_OPEN", "HDFC temporarily unavailable", "HDFC-FALLBACK");
    }

    // Generic fallback:
    public GatewayResponse hdfcFallback(String merchantId, long amount, Exception ex) {
        return new GatewayResponse("ERROR", "Gateway error: " + ex.getMessage(), "HDFC-FALLBACK");
    }

    // ORDER MATTERS:
    // @CircuitBreaker is outer: if circuit OPEN → CallNotPermittedException → fallback (no bulkhead needed)
    // @Bulkhead is inner: if bulkhead full → BulkheadFullException → fallback
    // Both working: request goes through CircuitBreaker → Bulkhead → actual call
}

