class HdfcGatewayTest {
    @Autowired HdfcGatewayService svc;
    @Test void normalCall_succeeds(){
        GatewayResponse r=svc.charge("MRC-001",50000L);
        assertEquals("SUCCESS",r.status());
    }
}

