import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Duration;

@Service
public class MonitoredBulkheadService {
    private final Bulkhead bulkhead;
    private final MeterRegistry metrics;

    MonitoredBulkheadService(MeterRegistry m) {
        metrics = m;
        bulkhead = Bulkhead.of("hdfc-monitored",
            BulkheadConfig.custom()
                .maxConcurrentCalls(3)
                .maxWaitDuration(Duration.ofMillis(0))
                .build());

        // Gauge: current available permits
        Gauge.builder("bulkhead.available_calls", bulkhead,
                b -> b.getMetrics().getAvailableConcurrentCalls())
            .tag("name", "hdfc")
            .register(metrics);
    }

    public String call() {
        if (!bulkhead.tryAcquirePermission()) {
            Counter.builder("bulkhead.rejected_calls")
                .tag("name", "hdfc")
                .register(metrics).increment();
            return "REJECTED";
        }
        try {
            return "SUCCESS";
        } finally {
            bulkhead.onComplete();
        }
    }

    public Bulkhead getBulkhead() { return bulkhead; }
}

@SpringBootTest
class BulkheadMetricsTest {
    @Autowired MonitoredBulkheadService svc;
    @Autowired MeterRegistry registry;

    @Test void gauge_readsAvailablePermits(){
        double available = registry.get("bulkhead.available_calls")
            .tag("name","hdfc").gauge().value();
        assertEquals(3.0, available); // 3 permits at start
    }

    @Test void rejected_counter_increments(){
        // Exhaust permits:
        svc.getBulkhead().tryAcquirePermission(); // 1
        svc.getBulkhead().tryAcquirePermission(); // 2
        svc.getBulkhead().tryAcquirePermission(); // 3 (full)

        svc.call(); // 4th: rejected → counter increments

        double rejected = registry.counter("bulkhead.rejected_calls","name","hdfc").count();
        assertEquals(1.0, rejected);
    }
}

