import io.github.resilience4j.bulkhead.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.concurrent.CompletableFuture;
import java.time.Duration;

@Service
public class ThreadPoolBulkheadService {
    private final ThreadPoolBulkhead bulkhead;

    ThreadPoolBulkheadService() {
        this.bulkhead = ThreadPoolBulkhead.of("hdfc-threadpool",
            ThreadPoolBulkheadConfig.custom()
                .coreThreadPoolSize(5)      // Reduced for test
                .maxThreadPoolSize(10)
                .queueCapacity(5)
                .keepAliveDuration(Duration.ofSeconds(60))
                .build());
    }

    // Executes in HDFC's dedicated thread pool:
    public CompletableFuture<String> callHdfc(String merchantId, long amount) {
        return bulkhead.executeSupplier(() -> {
            // This runs in HDFC's thread pool (not Tomcat's)
            // If HDFC pool is full: BulkheadFullException thrown
            return "SUCCESS: " + merchantId + " charged " + amount;
        });
    }

    // WHY THREAD-POOL vs SEMAPHORE:
    // Semaphore: limits concurrency but uses SAME Tomcat threads
    //   If HDFC blocks for 10s: Tomcat threads are stuck
    // Thread-pool: HDFC uses its OWN threads
    //   Tomcat threads never wait for HDFC
    //   executeSupplier returns CompletableFuture immediately to Tomcat thread
    //   HDFC execution happens on the HDFC thread pool
    // Use thread-pool for: blocking I/O (RestTemplate, JDBC)
    // Use semaphore for: reactive/non-blocking (WebClient)

    public ThreadPoolBulkhead getBulkhead() { return bulkhead; }
}

@SpringBootTest
class ThreadPoolBulkheadTest {
    @Autowired ThreadPoolBulkheadService svc;

    @Test void callHdfc_returnsResult() throws Exception {
        CompletableFuture<String> future = svc.callHdfc("MRC-001", 50000L);
        String result = future.get();
        assertTrue(result.contains("SUCCESS"));
        assertTrue(result.contains("MRC-001"));
    }
}

