import io.github.resilience4j.bulkhead.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Duration;

@Service
class GatewayBulkheadSuite {
    final Bulkhead hdfc=make("hdfc",5);
    final Bulkhead visa=make("visa",5);
    final Bulkhead kyc=make("kyc",5);

    private Bulkhead make(String n,int m){
        return Bulkhead.of(n,BulkheadConfig.custom().maxConcurrentCalls(m)
            .maxWaitDuration(Duration.ofMillis(0)).build());
    }

    public String route(String merchant,String preferred){
        // Try preferred gateway first:
        Bulkhead preferred_bh=selectBh(preferred);
        if(preferred_bh!=null&&preferred_bh.tryAcquirePermission()){
            try{return "SUCCESS:"+preferred;}finally{preferred_bh.onComplete();}
        }
        // Try VISA as fallback:
        if(!"VISA".equals(preferred)&&visa.tryAcquirePermission()){
            try{return "SUCCESS:VISA-FALLBACK";}finally{visa.onComplete();}
        }
        // Try KYC as fallback:
        if(kyc.tryAcquirePermission()){
            try{return "SUCCESS:KYC-FALLBACK";}finally{kyc.onComplete();}
        }
        return "FALLBACK:ALL_GATEWAYS_FULL";
    }

    private Bulkhead selectBh(String name){
        return switch(name){case"HDFC"->hdfc;case"VISA"->visa;case"KYC"->kyc;default->null;};
    }

    void exhaustBulkhead(Bulkhead bh){
        while(bh.tryAcquirePermission()); // drain all permits (don't release)
    }
}

@SpringBootTest
class GatewayRoutingTest {
    @Autowired GatewayBulkheadSuite suite;
    @Test void hdfc_works(){assertEquals("SUCCESS:HDFC",suite.route("MRC","HDFC"));}
    @Test void hdfcFull_visaFallback(){
        suite.exhaustBulkhead(suite.hdfc);
        assertTrue(suite.route("MRC","HDFC").contains("VISA"));
    }
    @Test void hdfcAndVisaFull_kycFallback(){
        suite.exhaustBulkhead(suite.hdfc);
        suite.exhaustBulkhead(suite.visa);
        assertTrue(suite.route("MRC","HDFC").contains("KYC"));
    }
    @Test void allFull_ultimateFallback(){
        suite.exhaustBulkhead(suite.hdfc);
        suite.exhaustBulkhead(suite.visa);
        suite.exhaustBulkhead(suite.kyc);
        assertEquals("FALLBACK:ALL_GATEWAYS_FULL",suite.route("MRC","HDFC"));
    }
}

