//     Index         payment-logs
//     Type          _doc
//
// BENEFIT: payment-service logs go to file → Fluent Bit ships to Elasticsearch
// No logging SDK in payment-service code (just standard SLF4J)

@Service
public class StructuredPaymentLogger {
    private static final Logger log = LoggerFactory.getLogger(StructuredPaymentLogger.class);
    private final ObjectMapper mapper;

    StructuredPaymentLogger(ObjectMapper m) { mapper = m; }

    // Log as JSON for Fluent Bit to parse:
    public void logPaymentCreated(String traceId, String merchantId, long amountPaise) {
        try {
            String json = mapper.writeValueAsString(Map.of(
                "event", "payment_created",
                "traceId", traceId,
                "merchantId", merchantId,
                "amountPaise", amountPaise,
                "timestamp", System.currentTimeMillis()
            ));
            log.info(json); // Written to log file → Fluent Bit reads and ships
        } catch (Exception e) {
            log.error("Failed to serialize log: {}", e.getMessage());
        }
    }

    String buildLogJson(String traceId, String merchantId, long amount) throws Exception {
        return mapper.writeValueAsString(Map.of(
            "event","payment_created","traceId",traceId,
            "merchantId",merchantId,"amountPaise",amount));
    }
}

@SpringBootTest
class StructuredLogTest {
    @Autowired StructuredPaymentLogger logger;
    @Autowired ObjectMapper mapper;

    @Test void logJson_isParseable() throws Exception {
        String json = logger.buildLogJson("TRACE-123","MRC-001",50000L);
        Map<?,?> parsed = mapper.readValue(json,Map.class);
        assertEquals("payment_created",parsed.get("event"));
        assertEquals("TRACE-123",parsed.get("traceId"));
        assertEquals(50000,parsed.get("amountPaise"));
    }
}

