@Service class SynthBulkheadSvc {
    private final MeterRegistry m;
    private final Bulkhead bh=Bulkhead.of("synth",BulkheadConfig.custom()
        .maxConcurrentCalls(3).maxWaitDuration(Duration.ofMillis(0)).build());
    SynthBulkheadSvc(MeterRegistry m){
        this.m=m;
        Gauge.builder("synth.available",bh,b->b.getMetrics().getAvailableConcurrentCalls()).register(m);
    }
    String call(){
        if(!bh.tryAcquirePermission()){
            Counter.builder("synth.rejected").register(m).increment();
            return "FALLBACK";
        }
        try{return "SUCCESS";}finally{bh.onComplete();}
    }
    void exhaust(){while(bh.tryAcquirePermission());}
    double available(){return m.get("synth.available").gauge().value();}
    double rejected(){return m.counter("synth.rejected").count();}
}

@Service class SynthLogger {
    private final ObjectMapper mapper;
    SynthLogger(ObjectMapper m){mapper=m;}
    String toJson(String event,String id) throws Exception{
        return mapper.writeValueAsString(Map.of("event",event,"id",id,"ts",System.currentTimeMillis()));
    }
    boolean isValidJson(String json){
        try{mapper.readValue(json,Map.class);return true;}catch(Exception e){return false;}
    }
}

record GatewayHealth(String name,double available,double rejected){}

@Service class GatewayHealthReport {
    private final SynthBulkheadSvc bh;
    GatewayHealthReport(SynthBulkheadSvc b){bh=b;}
    GatewayHealth report(){return new GatewayHealth("SYNTH",bh.available(),bh.rejected());}
}

@SpringBootTest
class M24T5SynthesisTest {
    @Autowired SynthBulkheadSvc bh;
    @Autowired SynthLogger logger;
    @Autowired GatewayHealthReport report;

    @Test void normalCall_succeeds(){assertEquals("SUCCESS",bh.call());}
    @Test void bulkheadFull_fallback(){
        bh.exhaust();
        assertEquals("FALLBACK",bh.call());
    }
    @Test void metric_rejected(){
        bh.exhaust();
        bh.call();
        assertTrue(bh.rejected()>=1.0);
    }
    @Test void log_isJson() throws Exception {
        String json=logger.toJson("payment_created","PAY-001");
        assertTrue(logger.isValidJson(json));
        assertTrue(json.contains("payment_created"));
    }
}
